void CLIPLINE(Real64 &x0, Real64 &x1, Real64 &y0, Real64 &y1, Real64 maxX, Real64 minX, Real64 maxY, Real64 minY, bool &visible)
{

    // Line segment clipping
    // Reference:
    // Liang, Y.D., Barsky, B.A., Slater, M.
    // 2D line and polygon clipping based on space subdivision.
    // The Visual Computer 10, 407–422 (1994).

    // Tweaked via microbenchmarking to improve efficiency

    bool rev = false;
    if (x0 > x1) { // reverse for efficiency
        std::swap(x0, x1);
        std::swap(y0, y1);
        rev = true;
    }

    if (x0 > maxX || x1 < minX) {
        // Both points are outside the clip window, so they can't cross it
        return;
    }

    // defining variables
    Real64 const dx = x1 - x0; // >= 0
    Real64 const dy = y1 - y0;

    Real64 const q1 = x0 - minX;
    Real64 const q2 = maxX - x0;
    Real64 const q3 = y0 - minY;
    Real64 const q4 = maxY - y0;

    Real64 u1 = 0;
    Real64 u2 = 1;

    if ((dx == 0 && (q1 < 0 || q2 < 0)) || (dy == 0 && (q3 < 0 || q4 < 0))) {
        // Line is parallel to clipping window
        return;
    }
    if (dx != 0) {
        Real64 const r1 = q1 / -dx;
        if (r1 > u1) {
            u1 = r1;
        }
        Real64 const r2 = q2 / dx;
        if (r2 < u2) {
            u2 = r2;
        }
    }
    if (dy != 0) {
        Real64 const r3 = q3 / -dy;
        Real64 const r4 = q4 / dy;
        if (dy > 0) {
            if (r3 > u1) {
                u1 = r3;
            }
            if (r4 < u2) {
                u2 = r4;
            }
        } else {
            if (r4 > u1) {
                u1 = r4;
            }
            if (r3 < u2) {
                u2 = r3;
            }
        }
    }

    if (u1 > u2) { // reject
        // Line is outside the clipping window
        return;
    }

    visible = true;

    Real64 const xn0 = x0 + dx * u1;
    Real64 const yn0 = y0 + dy * u1;

    Real64 const xn1 = x0 + dx * u2;
    Real64 const yn1 = y0 + dy * u2;

    if (rev) {
        x0 = xn1;
        y0 = yn1;
        x1 = xn0;
        y1 = yn0;
    } else {
        x0 = xn0;
        y0 = yn0;
        x1 = xn1;
        y1 = yn1;
    }
}

void SUN3(int const JulianDayOfYear,      // Julian Day Of Year
          Real64 &SineOfSolarDeclination, // Sine of Solar Declination
          Real64 &EquationOfTime          // Equation of Time (Degrees)
)
{

    // SUBROUTINE INFORMATION:
    //       AUTHOR         Legacy Code
    //       DATE WRITTEN
    //       MODIFIED       na
    //       RE-ENGINEERED  Linda K. Lawrie

    // PURPOSE OF THIS SUBROUTINE:
    // This subroutine computes the coefficients for determining
    // the solar position.

    // METHODOLOGY EMPLOYED:
    // The expressions are based on least-squares fits of data on p.316 of 'Thermal
    // Environmental Engineering' by Threlkeld and on p.387 of the ASHRAE Handbook
    // of Fundamentals (need date of ASHRAE HOF).

    // REFERENCES:
    // BLAST/IBLAST code, original author George Walton

    // Fitted coefficients of Fourier series | Sine of declination coefficients
    static constexpr std::array<Real64, 9> SineSolDeclCoef = {
        0.00561800, 0.0657911, -0.392779, 0.00064440, -0.00618495, -0.00010101, -0.00007951, -0.00011691, 0.00002096};
    // Fitted coefficients of Fourier Series | Equation of Time coefficients
    static constexpr std::array<Real64, 9> EqOfTimeCoef = {
        0.00021971, -0.122649, 0.00762856, -0.156308, -0.0530028, -0.00388702, -0.00123978, -0.00270502, -0.00167992};

    // SUBROUTINE LOCAL VARIABLE DECLARATIONS:
    Real64 X;     // Day of Year in Radians (Computed from Input JulianDayOfYear)
    Real64 CosX;  // COS(X)
    Real64 SineX; // SIN(X)

    X = 0.017167 * JulianDayOfYear; // Convert julian date to angle X

    // Calculate sines and cosines of X
    SineX = std::sin(X);
    CosX = std::cos(X);

    SineOfSolarDeclination = SineSolDeclCoef[0] + SineSolDeclCoef[1] * SineX + SineSolDeclCoef[2] * CosX + SineSolDeclCoef[3] * (SineX * CosX * 2.0) +
                             SineSolDeclCoef[4] * (pow_2(CosX) - pow_2(SineX)) +
                             SineSolDeclCoef[5] * (SineX * (pow_2(CosX) - pow_2(SineX)) + CosX * (SineX * CosX * 2.0)) +
                             SineSolDeclCoef[6] * (CosX * (pow_2(CosX) - pow_2(SineX)) - SineX * (SineX * CosX * 2.0)) +
                             SineSolDeclCoef[7] * (2.0 * (SineX * CosX * 2.0) * (pow_2(CosX) - pow_2(SineX))) +
                             SineSolDeclCoef[8] * (pow_2(pow_2(CosX) - pow_2(SineX)) - pow_2(SineX * CosX * 2.0));

    EquationOfTime = EqOfTimeCoef[0] + EqOfTimeCoef[1] * SineX + EqOfTimeCoef[2] * CosX + EqOfTimeCoef[3] * (SineX * CosX * 2.0) +
                     EqOfTimeCoef[4] * (pow_2(CosX) - pow_2(SineX)) +
                     EqOfTimeCoef[5] * (SineX * (pow_2(CosX) - pow_2(SineX)) + CosX * (SineX * CosX * 2.0)) +
                     EqOfTimeCoef[6] * (CosX * (pow_2(CosX) - pow_2(SineX)) - SineX * (SineX * CosX * 2.0)) +
                     EqOfTimeCoef[7] * (2.0 * (SineX * CosX * 2.0) * (pow_2(CosX) - pow_2(SineX))) +
                     EqOfTimeCoef[8] * (pow_2(pow_2(CosX) - pow_2(SineX)) - pow_2(SineX * CosX * 2.0));
}

void linint(Real64 const x1, Real64 const x2, Real64 const y1, Real64 const y2, Real64 const x, Real64 &y)
    {

        y = (y2 - y1) / (x2 - x1) * (x - x1) + y1; // Autodesk:DivZero Should protect against divide by zero
    }

void film(Real64 const tex, Real64 const tw, Real64 const ws, int const iwd, Real64 &hcout, int const ibc)
{
    //***********************************************************************
    // purpose - to find outdoor film coeff
    //***********************************************************************
    // Inputs -
    //   tex - outdoor air temp [k]
    //   tw - outside surface temp
    //   ws - wind speed [m/s]
    //   iwd - wind direction [0 - windward; 1 - leeward]
    // Outputs
    //   hcout - convective film coeff [w m-2 k-1]

    // Locals
    Real64 constexpr conv(5.6783);

    Real64 vc;
    Real64 acoef;
    Real64 bexp;

    // calculation of convection component of exterior film coefficient using the :
    switch (ibc) {
    case 0: { // ISO 15099
        hcout = 4.0 + 4.0 * ws;
    } break;
    case -1: {          // old ASHRAE SPC142 correlation
        if (iwd == 0) { // windward
            if (ws > 2.0) {
                vc = 0.25 * ws;
            } else {
                vc = 0.5;
            }
        } else { // leeward
            vc = 0.3 + 0.05 * ws;
        }
        hcout = 3.28 * std::pow(vc, 0.605);
        hcout *= conv; // convert to metric
    } break;
    case -2: {          // Yazdanian-Klems correlation:
        if (iwd == 0) { // windward
            acoef = 2.38;
            bexp = 0.89;
        } else { // leeward
            acoef = 2.86;
            bexp = 0.617;
        }
        hcout = std::sqrt(pow_2(0.84 * std::pow(tw - tex, 0.33)) + pow_2(acoef * std::pow(ws, bexp)));
    } break;
    case -3: {          // Kimura correlation (Section 8.4.2.3 in ISO 15099-2001):
        if (iwd == 0) { // windward
            if (ws > 2.0) {
                vc = 0.25 * ws;
            } else {
                vc = 0.5 * ws;
            }
        } else { // leeward
            vc = 0.3 + 0.05 * ws;
        }
        hcout = 4.7 + 7.6 * vc;
    } break;
    default:
        break;
    }
}

void CalcIBesselFunc(Real64 const BessFuncArg, int const BessFuncOrd, Real64 &IBessFunc, int &ErrorCode)
{
    // SUBROUTINE INFORMATION:
    //       AUTHOR   Unknown
    //       DATE WRITTEN   Unknown
    //       DATE REWRITTEN  April 1997 by Russell D. Taylor, Ph.D.
    //       MODIFIED
    //       RE-ENGINEERED

    // PURPOSE OF THIS SUBROUTINE:
    // To calculate the modified Bessel Function from order 0 to BessFuncOrd
    // BessFuncArg    ARGUMENT OF BESSEL FUNCTION
    // BessFuncOrd    ORDER OF BESSEL FUNCTION, GREATER THAN OR EQUAL TO ZERO
    // IBessFunc   RESULTANT VALUE OF I BESSEL FUNCTION
    // ErrorCode  RESULTANT ERROR CODE:
    //       ErrorCode = 0   NO ERROR
    //       ErrorCode = 1   BessFuncOrd .LT. 0
    //       ErrorCode = 2   BessFuncArg .LT. 0
    //       ErrorCode = 3   IBessFunc .LT. 10**(-30),     IBessFunc IS SET TO 0
    //       ErrorCode = 4   BessFuncArg .GT. BessFuncOrd & BessFuncArg .GT. 90,  IBessFunc IS SET TO 10**38

    // REFERENCES:
    // First found in MODSIM.

    // USE STATEMENTS:
    // na

    // Locals
    // SUBROUTINE ARGUMENT DEFINITIONS:

    // SUBROUTINE PARAMETER DEFINITIONS:
    Real64 constexpr ErrorTol(1.0e-06);

    // INTERFACE BLOCK SPECIFICATIONS
    // na

    // DERIVED TYPE DEFINITIONS
    // na

    // SUBROUTINE LOCAL VARIABLE DECLARATIONS:
    int LoopCount;

    Real64 FI;
    Real64 FK;
    Real64 TERM;

    ErrorCode = 0;
    IBessFunc = 1.0;
    if (BessFuncArg == 0.0 && BessFuncOrd == 0) {
        return;
    }

    if (BessFuncOrd < 0) {
        ErrorCode = 1;
        return;
    }
    if (BessFuncArg < 0.0) {
        ErrorCode = 2;
        return;
    }
    if (BessFuncArg > 12.0 && BessFuncArg > BessFuncOrd) {
        if (BessFuncArg > 90.0) {
            ErrorCode = 4;
            IBessFunc = 1.0e30;
            return;
        }
        TERM = 1.0;
        IBessFunc = 1.0;
        for (LoopCount = 1; LoopCount <= 30; ++LoopCount) { // Start of 1st LoopCount Loop
            if (std::abs(TERM) <= std::abs(ErrorTol * IBessFunc)) {
                IBessFunc *= std::exp(BessFuncArg) / std::sqrt(2.0 * Constant::Pi * BessFuncArg);
                return;
            }
            TERM *= 0.125 / BessFuncArg * (pow_2(2 * LoopCount - 1) - 4 * BessFuncOrd * BessFuncOrd) / double(LoopCount);
            IBessFunc += TERM;
        } // End of 1st LoopCount loop
    }

    TERM = 1.0;
    if (BessFuncOrd > 0) {
        for (LoopCount = 1; LoopCount <= BessFuncOrd; ++LoopCount) { // Start of 2nd LoopCount Loop
            FI = LoopCount;
            if (std::abs(TERM) < 1.0e-30 * FI / (BessFuncArg * 2.0)) {
                ErrorCode = 3;
                IBessFunc = 0.0;
                return;
            }
            TERM *= BessFuncArg / (2.0 * FI);
        } // End of 2nd LoopCount loop
    }

    IBessFunc = TERM;
    for (LoopCount = 1; LoopCount <= 1000; ++LoopCount) { // Start of 3rd LoopCount Loop
        if (std::abs(TERM) <= std::abs(IBessFunc * ErrorTol)) {
            return;
        }
        FK = LoopCount * (BessFuncOrd + LoopCount);
        TERM *= pow_2(BessFuncArg) / (4.0 * FK);
        IBessFunc += TERM;
    } // End of  3rd LoopCount loop
}

void SetDayOfWeekInitialValues(int const EnvironDayOfWeek, // Starting Day of Week for the (Weather) RunPeriod (User Input)
                                   int &currentDayOfWeek       // Current Day of Week
    )
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Linda Lawrie
        //       DATE WRITTEN   March 2012

        // PURPOSE OF THIS SUBROUTINE:
        // Set of begin day of week for an environment.  Similar sets but slightly different
        // conditions.  Improve code readability by having three routine calls instead of three
        // IF blocks.

        if (EnvironDayOfWeek != 0) {
            if (EnvironDayOfWeek <= 7) {
                currentDayOfWeek = EnvironDayOfWeek - 1;
            } else {
                currentDayOfWeek = EnvironDayOfWeek;
            }
        }
    }

void OPENNESS_LW(Real64 const OPENNESS, // shade openness (=tausbb at normal incidence)
                 Real64 const EPSLW0,   // apparent LW emittance of shade at 0 openness
                 Real64 const TAULW0,   // apparent LW transmittance of shade at 0 openness
                 Real64 &EPSLW,         // returned: effective LW emittance of shade
                 Real64 &TAULW          // returned: effective LW transmittance of shade
)
{
    // SUBROUTINE INFORMATION:
    //       AUTHOR         John L. Wright and Nathan Kotey, University of Waterloo,
    //                      Mechanical Engineering, Advanced Glazing System Laboratory

    // PURPOSE OF THIS SUBROUTINE:
    // Modifies long wave properties for shade types characterized by openness.
    // Applies to shade type: insect screen, roller blind, drape fabric

    //   (= wire or thread emittance)
    //   typical (default) values
    //      dark insect screen = .93
    //      metallic insect screen = .32
    //      roller blinds = .91
    //      drape fabric = .87
    //   typical (default) values
    //      dark insect screen = .02
    //      metallic insect screen = .19
    //      roller blinds = .05
    //      drape fabric = .05

    EPSLW = EPSLW0 * (1.0 - OPENNESS);
    TAULW = TAULW0 * (1.0 - OPENNESS) + OPENNESS;
}

bool Specular_OffNormal(Real64 const THETA, // solar beam angle of incidence, from normal radians
                        Real64 &RAT_1MR,    // returned: ratio of off-normal to normal solar (1-reflectance)
                        Real64 &RAT_TAU     // returned: ratio of off-normal to normal solar transmittance
)
{
    // FUNCTION INFORMATION:
    //       AUTHOR         JOHN L. WRIGHT, University of Waterloo, Mechanical Engineering
    //                      Advanced Glazing System Laboratory
    //       DATE WRITTEN   unknown
    //       MODIFIED       na
    //       RE-ENGINEERED  na

    // PURPOSE OF THIS FUNCTION:
    // Returns ratio of off-normal to normal of optical properties.
    // METHODOLOGY EMPLOYED:
    //  Uses a reference glass property.
    // returns TRUE if RAT_TAU < 1 or RAT_1MR < 1 (and thus Specular_Adjust s/b called)
    //    else FALSE
    // Return value
    bool Specular_OffNormal;

    // FUNCTION ARGUMENT DEFINITIONS:
    //    0 <= THETA <= PI/2
    //   NOTE: rhoAdj = 1-(1-rho)*RAT_1MR

    Real64 TAU0;
    Real64 RHO0;
    Real64 THETA1;
    Real64 THETA2;
    Real64 TAU_ON;
    Real64 RHO_ON;
    Real64 TAU_A;
    Real64 RPERP; // interface reflectance with respect to perpendicular
    Real64 RPARL;
    // and parallel polarization components of solar radiation
    Real64 TAUPERP;
    Real64 TAUPARL;
    Real64 RHOPERP;
    Real64 RHOPARL;
    Real64 N2; // reference refractive index for generating general off-normal
    //  curves for specular glazings
    Real64 KL; // extinction coefficient - thickness product, also used as a
    //  reference value to generate off-normal curves for specular layers

    Specular_OffNormal = true;
    THETA1 = std::abs(THETA);
    if (THETA1 > Constant::PiOvr2 - Constant::DegToRad) {
        // theta > 89 deg
        RAT_TAU = 0.0;
        RAT_1MR = 0.0;
    } else if (THETA1 >= Constant::DegToRad) {
        // theta >= 1 deg
        N2 = 1.526;
        KL = 55.0 * 0.006;
        TAU_A = std::exp(-1.0 * KL);
        RPERP = pow_2((N2 - 1.0) / (N2 + 1.0));
        TAU0 = TAU_A * (1.0 - RPERP) * (1.0 - RPERP) / (1.0 - (RPERP * RPERP * TAU_A * TAU_A));
        RHO0 = RPERP * (1.0 + (TAU_A * TAU0));
        THETA2 = std::asin((std::sin(THETA1)) / N2);
        TAU_A = std::exp(-1.0 * KL / std::cos(THETA2));
        RPERP = pow_2(std::sin(THETA2 - THETA1) / std::sin(THETA2 + THETA1));
        RPARL = pow_2(std::tan(THETA2 - THETA1) / std::tan(THETA2 + THETA1));
        TAUPERP = TAU_A * (1.0 - RPERP) * (1.0 - RPERP) / (1.0 - (RPERP * RPERP * TAU_A * TAU_A));
        TAUPARL = TAU_A * (1.0 - RPARL) * (1.0 - RPARL) / (1.0 - (RPARL * RPARL * TAU_A * TAU_A));
        RHOPERP = RPERP * (1.0 + (TAU_A * TAUPERP));
        RHOPARL = RPARL * (1.0 + (TAU_A * TAUPARL));
        TAU_ON = (TAUPERP + TAUPARL) / 2.0;
        RHO_ON = (RHOPERP + RHOPARL) / 2.0;
        RAT_TAU = TAU_ON / TAU0;
        RAT_1MR = (1.0 - RHO_ON) / (1.0 - RHO0);
    } else {
        Specular_OffNormal = false;
        RAT_TAU = 1.0;
        RAT_1MR = 1.0;
    }
    return Specular_OffNormal;
}
